/**
 * Run a replay and emit one ready-to-relay line per trace to stdout while it
 * runs, so a coding agent can background this command and simply show each new
 * line to the user (no parsing, no cadence decisions on the agent).
 *
 * The replay's own stdout (the ReplayResult JSON) is captured and appended as a
 * final `complete` event in the JSONL event log. This command's stdout carries
 * ONLY the progress lines (a header, one line per trace as it settles with its
 * pass/fail glyph + `n/total` + duration, and a final summary). Exits with the
 * replay's exit code.
 */
export declare function runReplayProgress(): Promise<void>;
